```kotlin
// Before
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    @Transactional(readOnly = true)
    fun getUserProfile(userId: String): UserProfileResponse {
        // 매 요청마다 DB 조회 (N+1 위험)
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("유저 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
        return UserProfileResponse.from(user, profile)
    }

    @Transactional
    fun updateProfile(userId: String, input: UpdateProfileInput): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음")
        profile.update(input)
        return UserProfileResponse.from(profileRepository.save(profile))
    }
}

// After
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    @Cacheable(
        cacheNames = [CacheConfig.USER_PROFILE],
        key = "#userId",
        unless = "#result == null",
    )
    @Transactional(readOnly = true)
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NotFoundException("유저 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
        return UserProfileResponse.from(user, profile)
    }

    @CachePut(
        cacheNames = [CacheConfig.USER_PROFILE],
        key = "#userId",
    )
    @Transactional
    fun updateProfile(userId: String, input: UpdateProfileInput): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
            ?: throw NotFoundException("프로필 없음")
        profile.update(input)
        return UserProfileResponse.from(profileRepository.save(profile))
    }

    @CacheEvict(
        cacheNames = [CacheConfig.USER_PROFILE],
        key = "#userId",
    )
    @Transactional
    fun deleteUser(userId: String) {
        userRepository.deleteById(userId)
    }
}
```

