### P1 - 팔로우 카운터 (RedisTemplate 직접 사용)

팔로우 수/팔로워 수는 빈번한 증감이 필요하므로 RedisTemplate의 INCR/DECR 원자성 연산을 사용합니다.

**파일: `user/src/main/kotlin/com/maum/backend/service/FollowService.kt`**

```kotlin
// Before
@Service
class FollowService(private val followRepository: FollowRepository) {
    @Transactional(readOnly = true)
    fun getFollowCount(userId: String): FollowCountResponse {
        // 매번 COUNT 쿼리 2회 실행
        val followingCount = followRepository.countByFollowerId(userId)
        val followerCount = followRepository.countByFollowingId(userId)
        return FollowCountResponse(followingCount, followerCount)
    }

    @Transactional
    fun follow(followerId: String, followingId: String) {
        followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
    }
}

// After
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        private fun followingKey(userId: String) = "follow:following:count:$userId"
        private fun followerKey(userId: String) = "follow:follower:count:$userId"
        private val TTL = Duration.ofMinutes(5)
    }

    @Transactional(readOnly = true)
    fun getFollowCount(userId: String): FollowCountResponse {
        val followingKey = followingKey(userId)
        val followerKey = followerKey(userId)

        // 캐시 미스 시 DB 조회 후 Redis에 적재
        val followingCount = redisTemplate.opsForValue().get(followingKey)?.toString()?.toLong()
            ?: followRepository.countByFollowerId(userId).also {
                redisTemplate.opsForValue().set(followingKey, it, TTL)
            }

        val followerCount = redisTemplate.opsForValue().get(followerKey)?.toString()?.toLong()
            ?: followRepository.countByFollowingId(userId).also {
                redisTemplate.opsForValue().set(followerKey, it, TTL)
            }

        return FollowCountResponse(followingCount, followerCount)
    }

    @Transactional
    fun follow(followerId: String, followingId: String) {
        followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
        // 원자적 카운터 증가
        redisTemplate.opsForValue().increment(followingKey(followerId))
        redisTemplate.opsForValue().increment(followerKey(followingId))
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        followRepository.deleteByFollowerIdAndFollowingId(followerId, followingId)
        redisTemplate.opsForValue().decrement(followingKey(followerId))
        redisTemplate.opsForValue().decrement(followerKey(followingId))
    }
}
```

**예상 개선 효과 (P1):**
- COUNT 쿼리: 요청당 2회 -> 캐시 히트 시 0회
- 응답 시간: 60ms -> 2ms (약 97% 단축)

