### 캐시 장애 대응: 서킷 브레이커 적용

Redis 장애 시 서비스 전체가 중단되지 않도록 fallback을 설정합니다.

**파일: `user/src/main/kotlin/com/maum/backend/config/CacheConfig.kt` (추가)**

```kotlin
@Bean
fun cacheErrorHandler(): CacheErrorHandler {
    return object : SimpleCacheErrorHandler() {
        private val log = LoggerFactory.getLogger(this::class.java)

        override fun handleCacheGetError(exception: RuntimeException, cache: Cache, key: Any) {
            log.warn("캐시 조회 실패 - cache: ${cache.name}, key: $key", exception)
            // 예외를 삼켜서 DB 조회로 fallback
        }

        override fun handleCachePutError(exception: RuntimeException, cache: Cache, key: Any, value: Any?) {
            log.warn("캐시 저장 실패 - cache: ${cache.name}, key: $key", exception)
        }

        override fun handleCacheEvictError(exception: RuntimeException, cache: Cache, key: Any) {
            log.error("캐시 삭제 실패 - cache: ${cache.name}, key: $key", exception)
        }
    }
}
